examples.table:
import { DataTable } from '@keter-ui/react';

<DataTable
  columns={[{ key: 'name', header: 'Name', sortable: true }]}
  data={[{ name: 'Alice' }, { name: 'Bob' }]}
  selectable
/>

examples.modal:
import { Modal, Button } from '@keter-ui/react';
import { useState } from 'react';

const [open, setOpen] = useState(false);
<Button onClick={() => setOpen(true)}>Open</Button>
<Modal isOpen={open} onClose={() => setOpen(false)} title="Confirm">
  <p>Are you sure?</p>
</Modal>

examples.rtl:
import { useLocaleDirection } from '@keter-ui/rtl';

function App({ locale }) {
  useLocaleDirection(locale); // auto-applies dir to <html>
  return <div>Content adapts to RTL automatically</div>;
}
